    uf = UnionFind(c)
    for u, v in connections:
        uf.union(u, v)

    component_min = [0] * (c + 1)
    for i in range(1, c + 1):
        component_min[i] = i

    component_count = [0] * (c + 1)
    for i in range(1, c + 1):
        component_count[i] = 1

    status = [True] * (c + 1)

    result = []

    for query in queries:
        if query[0] == 1:
            x = query[1]
            if status[x]:
                result.append(x)
            else:
                root = uf.find(x)
                min_node = component_min[root]
