import { UnionFind } from './UnionFind.js';

function solve(c, connections, queries) {
    // Build the grid using Union-Find
    const uf = new UnionFind(c);
    for (const [u, v] of connections) {
        uf.union(u, v);
    }

    // For each component, keep track of the minimum id
    const componentMin = new Array(c + 1).fill(0);
    for (let i = 1; i <= c; i++) {
        componentMin[i] = i; // Initially, the min is the node itself
    }

    // For each component, keep track of the number of online nodes
    const componentCount = new Array(c + 1).fill(0);
    for (let i = 1; i <= c; i++) {
        componentCount[i] = 1; // Initially, each node is online
    }

    // For each node, track its current status (online or offline)
    const status = new Array(c + 1).fill(true);

    const result = [];

    for (const [type, x] of queries) {
        if (type === 1) {
            // Maintenance query
            if (status[x]) {
                // The node is online, so it handles the query
                result.push(x);
            } else {
                // The node is offline, find the min online node in its component
                const root = uf.find(x);
                let minNode = componentMin[root];
                // Check if there are any online nodes in the component
                if (componentCount[root] > 0) {
                    result.push(minNode);
                } else {
                    result.push(-1);
                }
            }
        } else {
            // Offline query
            if (status[x]) {
                // Mark the node as offline
                status[x] = false;
                // Update the component min and count
                const root = uf.find(x);
                componentMin[root] = Math.min(componentMin[root], x);
                componentCount[root]--;
            }
        }
    }

    return result;
}

