    for u, v in connections:
        uf.union(u, v)

    component_min = [i for i in range(c + 1)]
    component_count = [1] * (c + 1)
    status = [True] * (c + 1)

    result = []

    for query in queries:
        if query[0] == 1:
            x = query[1]
            if status[x]:
                result.append(x)
            else:
                root = uf.find(x)
                if component_count[root] > 0:
                    result.append(component_min[root])
                else:
                    result.append(-1)
        else:
